<!doctype html>
<html lang="de">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>LaserTag Verden</title>
    <link rel="icon" type="image/png" sizes="32x32" href="../resources/favicon-32x32.png">
    <link rel="icon" type="image/png" sizes="16x16" href="../resources/favicon-16x16.png">
    <script>window.tailwind = { config: { corePlugins: { preflight: false } } };</script>
    <script src="https://cdn.tailwindcss.com"></script>
    <link rel="stylesheet" href="../Shared.css">
    <script src="../Shared.js" defer></script>
    <script src="reservieren.js" defer></script>
</head>
<body>
    <header id="MainHeader" class="relative h-[140px] w-full max-[910px]:h-[180px]">
        <div id="FixedHeaderContent" class="fixed z-[5] mt-2.5 flex w-full flex-col justify-between border-y-[5px] border-[#00aaaa] bg-[#151515] text-white transition-transform duration-200 ease-in-out max-[910px]:-translate-y-[270px]">
            <div id="HeaderContent" class="flex items-center p-2.5 max-[910px]:flex-col-reverse">
                <div id="HeaderToggle" class="hidden w-full cursor-pointer justify-center p-[5px] max-[910px]:flex" onclick="ToggleMainHeader()"><i id="HeaderToggleIcon" class="translate-y-[-4px] rotate-45 border-b-[3px] border-r-[3px] border-white p-[7px]"></i></div>
                <a href="../"><img src="../resources/LaserTagVerdenLogo.png" alt="LaserTag Verden" id="HeaderLogo" class="w-[var(--logo-w)]"></a>
                <nav id="HeaderNavigation" class="flex w-full max-[910px]:flex-col max-[910px]:items-center">
                    <div class="w-full max-[910px]:hidden"></div>
                    <a href="./" class="Nav_Link is-active m-[5px] border-b-[3px] border-[aqua] p-[5px] text-xl text-inherit no-underline whitespace-nowrap">PREISE & RESERVIEREN</a>
                    <a href="../galerie/" class="Nav_Link m-[5px] p-[5px] text-xl text-inherit no-underline whitespace-nowrap">GALERIE</a>
                    <a href="../infos/" class="Nav_Link m-[5px] p-[5px] text-xl text-inherit no-underline whitespace-nowrap">INFOS</a>
                    <a href="../uber-uns/" class="Nav_Link m-[5px] p-[5px] text-xl text-inherit no-underline whitespace-nowrap">ÜBER UNS</a>
                    <a href="../kontakt/" class="Nav_Link m-[5px] p-[5px] text-xl text-inherit no-underline whitespace-nowrap">KONTAKT</a>
                </nav>
            </div>
        </div>
    </header>

    <main class="flex flex-col items-center gap-8 px-[100px] py-[25px] max-[1260px]:px-[15px] max-[775px]:px-[5px]" data-booking-wizard>
        <aside class="sticky top-[120px] z-[3] hidden w-full max-w-[1180px] rounded-[22px] border border-[#00aaaa]/35 bg-[#151515]/95 p-4 shadow-[0_12px_30px_rgba(0,0,0,.45)] backdrop-blur lg:grid lg:grid-cols-4 lg:gap-4">
            <div><p class="text-sm uppercase tracking-[.12em] text-white/70">Angebot</p><p class="mt-1 text-[#73ffff]" data-summary-offer>Bitte wählen</p></div>
            <div><p class="text-sm uppercase tracking-[.12em] text-white/70">Termin</p><p class="mt-1 text-[#73ffff]" data-summary-date>Bitte wählen</p></div>
            <div><p class="text-sm uppercase tracking-[.12em] text-white/70">Start</p><p class="mt-1 text-[#73ffff]" data-summary-time>Bitte wählen</p></div>
            <div><p class="text-sm uppercase tracking-[.12em] text-white/70">Spieler</p><p class="mt-1 text-[#73ffff]"><span data-summary-count>8</span> Personen</p></div>
        </aside>

        <nav class="grid w-full max-w-[1180px] grid-cols-4 gap-2 max-[640px]:grid-cols-2" aria-label="Buchungsschritte">
            <button class="booking-tab rounded-xl border-2 border-[#00aaaa] bg-[#00aaaa]/20 px-3 py-2 text-left text-[#73ffff] shadow-[0_0_16px_rgba(0,170,170,0.18)]" type="button" data-step-target="offer"><span class="block font-[Arial,Helvetica,sans-serif] text-xs uppercase tracking-[.1em] text-white/70">Schritt 1</span><span class="mt-0.5 block text-[19px]">Angebot</span></button>
            <button class="booking-tab rounded-xl border border-white/10 bg-black/30 px-3 py-2 text-left text-white/70" type="button" data-step-target="schedule"><span class="block font-[Arial,Helvetica,sans-serif] text-xs uppercase tracking-[.1em] text-white/70">Schritt 2</span><span class="mt-0.5 block text-[19px]">Termin</span></button>
            <button class="booking-tab rounded-xl border border-white/10 bg-black/30 px-3 py-2 text-left text-white/70" type="button" data-step-target="account"><span class="block font-[Arial,Helvetica,sans-serif] text-xs uppercase tracking-[.1em] text-white/70">Schritt 3</span><span class="mt-0.5 block text-[19px]">Konto</span></button>
            <button class="booking-tab rounded-xl border border-white/10 bg-black/30 px-3 py-2 text-left text-white/70" type="button" data-step-target="confirm"><span class="block font-[Arial,Helvetica,sans-serif] text-xs uppercase tracking-[.1em] text-white/70">Schritt 4</span><span class="mt-0.5 block text-[19px]">Bestätigen</span></button>
        </nav>

        <section class="w-full max-w-[1180px]" data-booking-step="offer">
            <p class="rounded-[22px] border border-white/10 bg-[var(--ContentBoxBackground)] p-5 font-[Arial,Helvetica,sans-serif] text-white/80" data-services-status aria-live="polite">Angebote werden geladen...</p>
            <div data-services-list></div>
            <section class="mt-8 rounded-[25px] border border-white/10 bg-[var(--ContentBoxBackground)] p-6 shadow-[10px_10px_20px_black]"><div class="grid grid-cols-[auto_1fr] items-center gap-5 max-[850px]:grid-cols-1"><div class="flex h-20 w-20 items-center justify-center rounded-full border-2 border-[#00aaaa] text-[28px] text-[#73ffff]">+</div><div><p class="text-sm uppercase tracking-[.24em] text-[#73ffff]">Optional</p><h2 class="text-[28px]">Getränkeflat</h2><p class="mt-2 font-[Arial,Helvetica,sans-serif] text-lg leading-7 text-white/90">Für 9,90 € pro Person sind kleine Getränke sowie 1-Liter-Wasserflaschen dabei. Cola, Fanta und Sprite sind davon ausgenommen.</p></div></div></section>
        </section>

        <section class="hidden w-full max-w-[1180px] rounded-[25px] border border-white/10 bg-[var(--ContentBoxBackground)] p-6 shadow-[10px_10px_20px_black]" data-booking-step="schedule">
            <div class="mb-6 flex items-start justify-between gap-4 max-[760px]:flex-col"><div><p class="text-sm uppercase tracking-[.24em] text-[#73ffff]">Schritt 2</p><h1 class="mt-2 text-[32px]">Wann wollt ihr spielen?</h1><p class="mt-3 font-[Arial,Helvetica,sans-serif] text-lg">Ausgewählt: <span class="text-[#73ffff]" data-selected-offer>Bitte Angebot wählen</span></p></div><button class="Button_Book" type="button" data-go-step="offer">Angebot ändern</button></div>
            <div class="grid grid-cols-[minmax(0,1fr)_minmax(340px,.72fr)] gap-5 max-[980px]:grid-cols-1"><div class="rounded-[22px] border border-white/10 bg-black/25 p-4"><div class="flex items-center justify-between gap-4 max-[560px]:flex-col max-[560px]:items-stretch"><button class="rounded-2xl border border-white/15 bg-black/30 px-4 py-3 text-white/80" type="button" data-calendar-prev>Zurück</button><div class="text-center"><p class="text-sm uppercase tracking-[.12em] text-white/70">Datum wählen</p><h2 class="mt-1 text-[30px] text-[#73ffff]" data-calendar-title></h2></div><button class="rounded-2xl border border-white/15 bg-black/30 px-4 py-3 text-white/80" type="button" data-calendar-next>Weiter</button></div><div class="mt-5 grid grid-cols-7 gap-2 text-center font-[Arial,Helvetica,sans-serif] text-sm uppercase tracking-[.08em] text-white/50"><span>Mo</span><span>Di</span><span>Mi</span><span>Do</span><span>Fr</span><span>Sa</span><span>So</span></div><div class="mt-2 grid grid-cols-7 gap-2" data-calendar-grid></div><div class="mt-5 rounded-2xl border border-[#00aaaa]/35 bg-[#00aaaa]/10 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Ausgewählter Termin</p><p class="mt-1 text-[24px] text-[#73ffff]" data-selected-date></p><p class="mt-1 font-[Arial,Helvetica,sans-serif]">Start: <span data-selected-time>Bitte wählen</span></p></div></div>
                <aside class="flex flex-col gap-5"><div class="rounded-[22px] border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Teilnehmer</p><div class="mt-3 flex items-center justify-between rounded-2xl border border-white/15 bg-black/30 p-3"><button class="h-10 w-10 rounded-full border border-white/20 text-xl" type="button" data-count-down>-</button><output class="text-[30px] text-[#73ffff]" data-count>8</output><button class="h-10 w-10 rounded-full border border-[#00aaaa] text-xl text-[#73ffff]" type="button" data-count-up>+</button></div></div><div class="rounded-[22px] border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Zeitfenster</p><p class="mt-1 font-[Arial,Helvetica,sans-serif] text-base text-white/80">Beispielzeiten zur Auswahl. Die Verfügbarkeit wird nicht geprüft.</p><div class="mt-3 grid gap-2" data-time-list></div></div></aside>
            </div><div class="mt-6 flex justify-end"><button class="Button_Book" type="button" data-go-step="account">Weiter zum Konto</button></div>
        </section>

        <section class="hidden w-full max-w-[1180px] overflow-hidden rounded-[25px] border border-white/10 bg-[var(--ContentBoxBackground)] shadow-[10px_10px_20px_black]" data-booking-step="account"><div class="grid grid-cols-[.78fr_1fr] max-[980px]:grid-cols-1"><aside class="border-r border-white/10 bg-[radial-gradient(circle_at_top_left,rgba(0,170,170,.24),transparent_42%),rgba(0,0,0,.22)] p-6 max-[980px]:border-b max-[980px]:border-r-0"><p class="text-sm uppercase tracking-[.24em] text-[#73ffff]">Schritt 3</p><h1 class="mt-2 text-[34px] text-[#73ffff]">Wer bucht?</h1><p class="mt-3 font-[Arial,Helvetica,sans-serif] text-base text-white/90">Wählt aus, ob ihr ein bestehendes Konto nutzen oder ein neues Konto erstellen wollt.</p><div class="mt-6 grid gap-3"><button class="account-tab rounded-[22px] border border-[#00aaaa] bg-[#00aaaa]/20 p-4 text-left text-[#73ffff] shadow-[0_0_22px_rgba(0,170,170,.22)]" type="button" data-account="login"><span class="block text-sm uppercase tracking-[.12em] text-white/70">Bestehendes Konto</span><span class="mt-1 block text-[24px]">Einloggen</span><span class="mt-2 block font-[Arial,Helvetica,sans-serif] text-sm text-white/65">Schnell weiter mit gespeicherten Kundendaten.</span></button><button class="account-tab rounded-[22px] border border-white/15 bg-black/25 p-4 text-left text-white/70" type="button" data-account="register"><span class="block text-sm uppercase tracking-[.12em] text-white/70">Neu bei uns</span><span class="mt-1 block text-[24px]">Konto erstellen</span><span class="mt-2 block font-[Arial,Helvetica,sans-serif] text-sm text-white/65">Einmal registrieren und die Buchung direkt abschließen.</span></button></div></aside><div class="grid gap-5 p-6"><div class="rounded-[26px] border-2 border-[#00aaaa] bg-[#00aaaa]/10 p-5 shadow-[0_0_28px_rgba(0,170,170,.16)]" data-account-panel="login"><p class="text-sm uppercase tracking-[.12em] text-white/70">Login</p><h2 class="mt-1 text-[28px] text-[#73ffff]">Willkommen zurück</h2><p class="mt-3 font-[Arial,Helvetica,sans-serif] text-base text-white/90">Nutzt euer Kundenkonto, um den Termin ohne erneute Dateneingabe zu bestätigen.</p><div class="mt-5 grid grid-cols-2 gap-4 max-[700px]:grid-cols-1"><label class="text-sm uppercase tracking-[.12em] text-white/70">E-Mail<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="email" placeholder="kunde@example.de"></label><label class="text-sm uppercase tracking-[.12em] text-white/70">Passwort<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="password" placeholder="Passwort"></label></div><p class="mt-4 font-[Arial,Helvetica,sans-serif] text-sm text-white/60">Diese statische Vorschau übermittelt keine Anmeldedaten.</p><button class="Button_Book mt-5" type="button" data-go-step="confirm">Weiter zur Bestätigung</button></div><div class="hidden rounded-[26px] border-2 border-[#00aaaa] bg-[#00aaaa]/10 p-5 shadow-[0_0_28px_rgba(0,170,170,.16)]" data-account-panel="register"><p class="text-sm uppercase tracking-[.12em] text-white/70">Registrierung</p><h2 class="mt-1 text-[28px]">Neues Kundenkonto</h2><p class="mt-3 font-[Arial,Helvetica,sans-serif] text-base text-white/90">Erstellt ein Konto für diese und spätere Reservierungen.</p><div class="mt-5 grid grid-cols-2 gap-4 max-[700px]:grid-cols-1"><label class="text-sm uppercase tracking-[.12em] text-white/70">Name<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="text" placeholder="Max Mustermann"></label><label class="text-sm uppercase tracking-[.12em] text-white/70">Telefon<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="tel" placeholder="0123 456789"></label><label class="col-span-2 text-sm uppercase tracking-[.12em] text-white/70 max-[700px]:col-auto">E-Mail<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="email" placeholder="max@example.de"></label><label class="text-sm uppercase tracking-[.12em] text-white/70">Passwort<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="password"></label><label class="text-sm uppercase tracking-[.12em] text-white/70">Passwort wiederholen<input class="mt-2 w-full rounded-xl border border-white/15 bg-black/35 px-4 py-3 font-[Arial,Helvetica,sans-serif] text-white" type="password"></label></div><p class="mt-4 font-[Arial,Helvetica,sans-serif] text-sm text-white/60">Diese statische Vorschau erstellt kein Kundenkonto.</p><button class="Button_Book mt-5" type="button" data-go-step="confirm">Weiter zur Bestätigung</button></div></div></div></section>

        <section class="hidden w-full max-w-[1180px] rounded-[25px] border border-white/10 bg-[var(--ContentBoxBackground)] p-6 shadow-[10px_10px_20px_black]" data-booking-step="confirm"><div class="mb-6 flex items-center justify-between gap-4"><div><p class="text-sm uppercase tracking-[.24em] text-[#73ffff]">Schritt 4</p><h1 class="mt-2 text-[32px]">Buchung prüfen und bestätigen</h1></div><span class="rounded-full border border-[#00aaaa] px-3 py-1 font-[Arial,Helvetica,sans-serif] text-sm">Letzter Schritt</span></div><div class="grid grid-cols-[1fr_.72fr] gap-5 max-[900px]:grid-cols-1"><div class="rounded-[22px] border border-[#00aaaa]/35 bg-[#00aaaa]/10 p-5"><h2 class="text-[26px] text-[#73ffff]">Eure Auswahl</h2><div class="mt-5 grid grid-cols-2 gap-4 font-[Arial,Helvetica,sans-serif] max-[560px]:grid-cols-1"><div class="rounded-2xl border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Angebot</p><p class="mt-2 text-lg" data-confirm-offer>Bitte wählen</p></div><div class="rounded-2xl border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Teilnehmer</p><p class="mt-2 text-lg"><span data-confirm-count>8</span> Personen</p></div><div class="rounded-2xl border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Datum</p><p class="mt-2 text-lg" data-confirm-date>Bitte wählen</p></div><div class="rounded-2xl border border-white/10 bg-black/25 p-4"><p class="text-sm uppercase tracking-[.12em] text-white/70">Startzeit</p><p class="mt-2 text-lg" data-confirm-time>Bitte wählen</p></div></div></div><aside class="rounded-[22px] border border-white/10 bg-black/25 p-5"><h2 class="text-[26px]">Bereit?</h2><p class="mt-2 font-[Arial,Helvetica,sans-serif] text-base text-white/90">Prüft die Angaben ein letztes Mal. Danach kann die Buchung bestätigt werden.</p><button class="Button_Book mt-5 w-full" type="button" data-demo-submit>Buchung bestätigen</button><button class="mt-3 w-full rounded-2xl border border-white/15 bg-black/30 px-4 py-3 text-white/80" type="button" data-go-step="schedule">Termin ändern</button></aside></div><p class="mt-5 hidden rounded-2xl border border-[#00aaaa] bg-[#00aaaa]/20 p-4 font-[Arial,Helvetica,sans-serif] text-[#73ffff]" data-demo-message>Die Buchungsfunktion ist in dieser statischen Vorschau nicht aktiv.</p></section>
        <div class="fixed inset-0 z-50 hidden items-center justify-center bg-black/80 px-4 backdrop-blur-sm" data-booking-success>
            <section class="w-full max-w-[680px] rounded-[30px] border-2 border-[#00aaaa] bg-[var(--ContentBoxBackground)] p-8 text-center text-white shadow-[0_0_55px_rgba(0,170,170,0.45)] max-[560px]:p-5" role="dialog" aria-modal="true" aria-labelledby="booking-success-title">
                <div class="Success_Check mx-auto flex h-20 w-20 items-center justify-center rounded-full border-2 border-[#73ffff] bg-[#00aaaa]/25 text-[42px] text-[#73ffff] shadow-[0_0_28px_rgba(115,255,255,0.35)]">&#10003;</div>
                <p class="mt-6 justify-self-center text-sm uppercase tracking-[.24em] text-[#73ffff]">Reservierung erfolgreich</p>
                <h2 id="booking-success-title" class="mt-2 text-[38px] leading-tight text-[#73ffff] max-[560px]:text-[30px]">Euer Termin ist gebucht</h2>
                <p class="mt-4 font-[Arial,Helvetica,sans-serif] text-lg leading-7 text-white/90 max-[775px]:text-base">Die Buchung wurde verbindlich in unserem System hinterlegt. Bitte achtet auf eure E-Mails für weitere Informationen.</p>
                <div class="mt-6 grid grid-cols-3 gap-3 font-[Arial,Helvetica,sans-serif] max-[620px]:grid-cols-1" data-success-summary></div>
                <div class="mt-7 flex justify-center gap-3 max-[520px]:flex-col"><a class="Button_Book" href="./">Neue Reservierung</a><a class="rounded-2xl border border-white/15 bg-black/30 px-5 py-3 text-white/80 hover:border-[#00aaaa] hover:text-[#73ffff]" href="../">Zur Startseite</a></div>
            </section>
        </div>
    </main>

    <footer id="MainFooter" class="my-5 flex w-full justify-between border-y-2 border-[#00aaaa] bg-[#151515] p-2.5 text-white shadow-[0_-5px_15px_black]"><nav class="flex w-full items-center max-[670px]:flex-wrap max-[670px]:justify-center"><a href="../impressum/" class="m-[5px] p-[5px] text-xl text-inherit no-underline">IMPRESSUM</a><a href="../agb/" class="m-[5px] p-[5px] text-xl text-inherit no-underline">AGB</a><a href="../datenschutz/" class="m-[5px] p-[5px] text-xl text-inherit no-underline">DATENSCHUTZ</a><div class="w-full max-[670px]:hidden"></div><a href="../muttizettel/" class="m-[5px] p-[5px] text-xl text-inherit no-underline">MUTTIZETTEL</a></nav></footer>
</body>
</html>
